205	const processClaim = (
206	  step: ClaimStep,
207	  steps: Step[],
208	  remainingCapByPolicy: Map<number, number>,
209	): { payout: number; remainingCap: number } => {
210	  const policyStep = steps[step.policy] as QuoteStep;
211	  validateClaim(step.incident.damages, policyStep.items);
212	  const remaining =
213	    remainingCapByPolicy.get(step.policy) ?? initialCap(policyStep.items);
214	  const desired = desiredPayout(step.incident.damages, policyStep.items);
215	  const payout = Math.floor(Math.min(desired, remaining));
216	  const remainingCap = remaining - payout;
217	  remainingCapByPolicy.set(step.policy, remainingCap);
218	  return { payout, remainingCap };
219	};
220	
221	const firstQuoteIndex = (steps: Step[]): number =>
222	  steps.findIndex((step) => step.op === "quote");
223	
224	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
225	  const remainingCapByPolicy = new Map<number, number>();
226	  const firstQuote = firstQuoteIndex(scenario.steps);
227	  const results = scenario.steps.map((step, index) => {
228	    if (step.op === "quote") {
229	      const isFollowUp = index > firstQuote;
230	      return priceQuote(step.items, scenario.customer, isFollowUp);
231	    }
232	    return processClaim(step, scenario.steps, remainingCapByPolicy);
233	  });
234	  return { results };
235	};
